class Solution {
    public String resultingString(String s) {
        StringBuilder sb = new StringBuilder(s);
        while (true) {
            boolean removed = false;
            for (int i = 0; i < sb.length() - 1; i++) {
                char c1 = sb.charAt(i);
                char c2 = sb.charAt(i + 1);
                if (Math.abs(c1 - c2) == 1 || Math.abs(c1 - c2) == 25) {
                    sb.delete(i, i + 2);
                    removed = true;
                    break;
                }
            }
            if (!removed) break;
        }
        return sb.toString();
    }
}
```
